import type { CSSProperties } from 'react';
import { NumberField } from '@tale-ui/react/number-field';

type NumberFieldStyle = CSSProperties & {
  '--tale-number-field-width'?: string;
  '--tale-number-field-group-width'?: string;
};

const panelWidthFieldStyle: NumberFieldStyle = {
  '--tale-number-field-width': '20rem',
  '--tale-number-field-group-width': '8.75rem',
};

export function PanelWidthField() {
  return (
    <NumberField.Root
      defaultValue={920}
      minValue={200}
      maxValue={2400}
      formatOptions={{ useGrouping: false, maximumFractionDigits: 0 }}
      style={panelWidthFieldStyle}
    >
      <NumberField.Label>Default panel width (px)</NumberField.Label>
      <NumberField.Group>
        <NumberField.Decrement />
        <NumberField.Input />
        <NumberField.Increment />
      </NumberField.Group>
      <NumberField.Description>
        Width applied to newly opened panels before the user drags the splitter.
      </NumberField.Description>
    </NumberField.Root>
  );
}
